import { useMemo } from 'react'
import { Box, Button, Group, Paper, Slider, Stack, Text } from '@mantine/core'
import type { SearchField } from './types'

/** Ranking field metadata for the blend builder. */
const RANKING_FIELDS = [
  { field: 'rank_us_news_national', label: 'US News National' },
  { field: 'rank_us_news_liberal_arts', label: 'US News Liberal Arts' },
  { field: 'rank_forbes', label: 'Forbes' },
  { field: 'rank_washington_monthly_national', label: 'Wash. Monthly National' },
  { field: 'rank_washington_monthly_liberal_arts', label: 'Wash. Monthly L.A.' },
  { field: 'rank_niche', label: 'Niche' },
  { field: 'score_money', label: 'Money Score' },
]

interface RankingBlendBuilderProps {
  weights: Record<string, number>
  onChange: (weights: Record<string, number>) => void
  /** Available search fields — used to filter to ranking fields that exist in the schema. */
  fields?: SearchField[]
}

export function RankingBlendBuilder({ weights, onChange, fields }: RankingBlendBuilderProps) {
  // Filter to ranking fields that actually exist in the field schema
  const availableFields = useMemo(() => {
    if (!fields || fields.length === 0) return RANKING_FIELDS
    const fieldNames = new Set(fields.filter((f) => f.theme === 'RANKING').map((f) => f.name))
    return RANKING_FIELDS.filter((rf) => fieldNames.has(rf.field))
  }, [fields])

  const totalWeight = useMemo(
    () => Object.values(weights).reduce((sum, w) => sum + w, 0),
    [weights],
  )

  const hasWeights = totalWeight > 0

  function handleSliderChange(field: string, value: number) {
    onChange({ ...weights, [field]: value })
  }

  function handleReset() {
    onChange({})
  }

  return (
    <Paper p="sm" withBorder data-testid="ranking-blend-builder">
      <Text size="xs" fw={600} tt="uppercase" lts="0.05em" c="dimmed" mb="xs">
        Custom Ranking Blend
      </Text>

      <Stack gap="xs">
        {availableFields.map(({ field, label }) => {
          const value = weights[field] ?? 0
          const pct = totalWeight > 0 ? ((value / totalWeight) * 100).toFixed(0) : '0'

          return (
            <Box key={field} data-field={field}>
              <Group justify="space-between" gap="xs" mb={2}>
                <Text size="xs" fw={500}>
                  {label}
                </Text>
                <Text size="xs" c="dimmed" miw={60} ta="right">
                  {value > 0 ? `${value} (${pct}%)` : '0'}
                </Text>
              </Group>
              <Slider
                value={value}
                onChange={(v) => handleSliderChange(field, v)}
                min={0}
                max={100}
                step={5}
                size="sm"
                label={null}
                aria-label={`${label} weight`}
              />
            </Box>
          )
        })}

        {hasWeights && (
          <Group justify="flex-end" mt="xs">
            <Button variant="subtle" size="xs" onClick={handleReset}>
              Reset
            </Button>
          </Group>
        )}
      </Stack>
    </Paper>
  )
}

