      <Text size="xs" fw={600} tt="uppercase" lts="0.05em" c="dimmed" mb="xs">
        Custom Ranking Blend
      </Text>

      <Stack gap="xs">
        {availableFields.map(({ field, label }) => {
          const value = weights[field] ?? 0
          const pct = totalWeight > 0 ? ((value / totalWeight) * 100).toFixed(0) : '0'

          return (
            <Box key={field} data-field={field}>
              <Group justify="space-between" gap="xs" mb={2}>
                <Text size="xs" fw={500}>
                  {label}
                </Text>
                <Text size="xs" c="dimmed" miw={60} ta="right">
                  {value > 0 ? `${value} (${pct}%)` : '0'}
                </Text>
              </Group>
              <Slider
                value={value}
                onChange={(v) => handleSliderChange(field, v)}
                min={0}
                max={100}
                step={5}
                size="sm"
                label={null}
                aria-label={`${label} weight`}
              />
            </Box>
          )
        })}

        {hasWeights && (
          <Group justify="flex-end" mt="xs">
            <Button variant="subtle" size="xs" onClick={handleReset}>
              Reset
            </Button>
          </Group>
        )}
      </Stack>
    </Paper>
  )
}

import { useRef, useState } from 'react'
import {
  ActionIcon,
  Box,
  Button,
  Checkbox,
  Divider,
  Group,
  Popover,
  Stack,
  Text,
} from '@mantine/core'
import { ArrowDown, ArrowUp, Columns, GripVertical } from 'lucide-react'

import { outputFieldsByTheme } from './helpers'
import type { SearchOutputField } from './types'

interface ColumnPickerProps {
  outputFields: SearchOutputField[]
  visibleColumns: Set<string>
  onToggleColumn: (fieldName: string) => void
  columnOrder: string[]
  onReorderColumn: (fieldName: string, direction: 'up' | 'down') => void
  onSetColumnOrder: (order: string[]) => void
}

export function ColumnPicker({
  outputFields,
  visibleColumns,
  onToggleColumn,
  columnOrder,
  onReorderColumn,
  onSetColumnOrder,
}: ColumnPickerProps) {
  const visibleFields = outputFields.filter((f) => f.visibility !== 'HIDDEN')
  const groups = outputFieldsByTheme(visibleFields)

  // Build ordered list of visible columns (excluding pinned "name") for the reorder section
  const fieldsByName = new Map(outputFields.map((f) => [f.name, f]))
  const orderedVisible = columnOrder.filter(
    (name) => name !== 'name' && visibleColumns.has(name) && fieldsByName.has(name),
  )

  // Drag state
  const dragItem = useRef<number | null>(null)
  const dragOverItem = useRef<number | null>(null)
  const [draggingIdx, setDraggingIdx] = useState<number | null>(null)
  const [dragOverIdx, setDragOverIdx] = useState<number | null>(null)

  function handleDragStart(idx: number) {
    dragItem.current = idx
    setDraggingIdx(idx)
  }

  function handleDragEnter(idx: number) {
    dragOverItem.current = idx
    setDragOverIdx(idx)
  }

  function handleDragEnd() {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      // Reorder orderedVisible, then map back to full columnOrder
      const reordered = [...orderedVisible]
      const [removed] = reordered.splice(dragItem.current, 1)
      reordered.splice(dragOverItem.current, 0, removed)

      // Rebuild full column order: preserve items not in orderedVisible at their positions,
      // replace orderedVisible items with the reordered list
      const orderedVisibleSet = new Set(orderedVisible)
      const newOrder: string[] = []
      let reorderIdx = 0
      for (const name of columnOrder) {
        if (orderedVisibleSet.has(name)) {
          newOrder.push(reordered[reorderIdx++])
        } else {
          newOrder.push(name)
        }
      }
      onSetColumnOrder(newOrder)
    }
    dragItem.current = null
    dragOverItem.current = null
    setDraggingIdx(null)
    setDragOverIdx(null)
  }

  return (
    <Popover width={300} position="bottom-end" shadow="md">
      <Popover.Target>
        <Button variant="default" leftSection={<Columns size={16} />}>
          Columns
        </Button>
      </Popover.Target>
      <Popover.Dropdown>
        <Box style={{ maxHeight: 500, overflowY: 'auto' }}>
          <Stack gap="md">
            {groups.map((group) => (
              <Box key={group.theme}>
                <Text fw={600} fz="sm" mb="xs">
                  {group.label}
                </Text>
                <Stack gap="xs">
                  {group.fields.map((field) => {
                    const isName = field.name === 'name'
                    return (
                      <Group key={field.name} gap="xs">
                        <Checkbox
                          label={field.label}
                          checked={isName || visibleColumns.has(field.name)}
                          disabled={isName}
                          onChange={() => onToggleColumn(field.name)}
                          size="sm"
                        />
                      </Group>
                    )
                  })}
                </Stack>
              </Box>
            ))}

            {orderedVisible.length > 0 && (
              <>
                <Divider />
                <Box>
                  <Text fw={600} fz="sm" mb="xs">
                    Column Order
                  </Text>
                  <Stack gap={4}>
                    {orderedVisible.map((name, idx) => {
                      const field = fieldsByName.get(name)
                      if (!field) return null
                      const isDragging = draggingIdx === idx
                      const isDragOver = dragOverIdx === idx && draggingIdx !== idx
                      return (
                        <Group
                          key={name}
                          gap="xs"
                          justify="space-between"
                          wrap="nowrap"
                          draggable
                          onDragStart={() => handleDragStart(idx)}
                          onDragEnter={() => handleDragEnter(idx)}
                          onDragEnd={handleDragEnd}
                          onDragOver={(e) => e.preventDefault()}
                          data-testid={`column-order-item-${name}`}
                          style={{
                            opacity: isDragging ? 0.5 : 1,
                            borderTop: isDragOver ? '2px solid var(--mantine-color-brand-5)' : '2px solid transparent',
                            cursor: 'grab',
                            borderRadius: 4,
                            padding: '2px 0',
                          }}
                        >
                          <Group gap={4} wrap="nowrap" style={{ flex: 1, minWidth: 0 }}>
                            <GripVertical size={14} style={{ flexShrink: 0, color: 'var(--mantine-color-dimmed)' }} />
                            <Text fz="sm" truncate>
                              {field.label}
                            </Text>
                          </Group>
                          <Group gap={2} wrap="nowrap">
                            <ActionIcon
                              variant="subtle"
                              size="sm"
                              disabled={idx === 0}
                              onClick={() => onReorderColumn(name, 'up')}
                              aria-label={`Move ${field.label} up`}
                            >
                              <ArrowUp size={14} />
                            </ActionIcon>
                            <ActionIcon
                              variant="subtle"
                              size="sm"
                              disabled={idx === orderedVisible.length - 1}
                              onClick={() => onReorderColumn(name, 'down')}
                              aria-label={`Move ${field.label} down`}
                            >
                              <ArrowDown size={14} />
                            </ActionIcon>
                          </Group>
                        </Group>
                      )
                    })}
                  </Stack>
                </Box>
              </>
            )}
          </Stack>
        </Box>
      </Popover.Dropdown>
    </Popover>
  )
}

