import { describe, it, expect } from 'vitest'
import { screen } from '@testing-library/react'
import { renderWithMantine } from '@/test/render'
import { Button } from './button'

describe('Button', () => {
  it('renders with default variant', () => {
    renderWithMantine(<Button>Click me</Button>)
    expect(screen.getByRole('button', { name: 'Click me' })).toBeInTheDocument()
  })

  it.each([
    'default',
    'accent',
    'outline',
    'accent-outline',
    'ghost',
    'light',
    'link',
  ] as const)('renders %s variant without crashing', (variant) => {
    renderWithMantine(<Button variant={variant}>Test</Button>)
    expect(screen.getByRole('button', { name: 'Test' })).toBeInTheDocument()
  })

  it.each(['default', 'xs', 'compact-xs', 'sm', 'lg', 'xl', 'icon'] as const)(
    'renders %s size without crashing',
    (size) => {
      renderWithMantine(<Button size={size}>Test</Button>)
      expect(screen.getByRole('button', { name: 'Test' })).toBeInTheDocument()
    },
  )

  it('forwards ref', () => {
    let buttonEl: HTMLButtonElement | null = null
    renderWithMantine(<Button ref={(el) => (buttonEl = el)}>Ref</Button>)
    expect(buttonEl).toBeInstanceOf(HTMLButtonElement)
  })

  it('passes through HTML button props', () => {
    renderWithMantine(
      <Button type="submit" disabled>
        Submit
      </Button>,
    )
    const btn = screen.getByRole('button', { name: 'Submit' })
    expect(btn).toBeDisabled()
    expect(btn).toHaveAttribute('type', 'submit')
  })
})

