  it('is disabled when disabled prop is set', () => {
    renderWithMantine(<Button disabled>Disabled</Button>)
    expect(screen.getByRole('button')).toBeDisabled()
  })

  it('renders all variant types', () => {
    const variants = ['default', 'accent', 'outline', 'accent-outline', 'ghost', 'link'] as const
    for (const v of variants) {
      const { unmount } = renderWithMantine(<Button variant={v}>{v}</Button>)
      expect(screen.getByRole('button', { name: v })).toBeInTheDocument()
      unmount()
    }
  })
})

